.hdg-card {
  display: flex;
  flex-direction: column;
  align-items: center;
  padding: 24px;
  gap: 16px;
  font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif;
  color: #1a1a1a;
}

/* Upload area */
.upload-area {
  width: 100%;
  max-width: 400px;
  min-height: 200px;
  border: 3px dashed #d1d5db;
  border-radius: 16px;
  display: flex;
  align-items: center;
  justify-content: center;
  cursor: pointer;
  transition: border-color 0.2s, background 0.2s;
  position: relative;
}

.upload-area:hover,
.upload-area.drag-over {
  border-color: #f97316;
  background: #fff7ed;
}

.upload-placeholder {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 8px;
  pointer-events: none;
}

.upload-icon {
  font-size: 48px;
}

.upload-text {
  font-size: 16px;
  color: #6b7280;
  font-weight: 500;
}

#file-input {
  position: absolute;
  width: 100%;
  height: 100%;
  opacity: 0;
  cursor: pointer;
}

/* Preview */
.preview-area {
  width: 100%;
  max-width: 400px;
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 12px;
}

#preview-img {
  width: 100%;
  border-radius: 12px;
  object-fit: cover;
  max-height: 300px;
}

.loading-state {
  display: flex;
  align-items: center;
  gap: 10px;
  font-size: 15px;
  color: #6b7280;
  font-weight: 500;
}

.spinner {
  width: 20px;
  height: 20px;
  border: 3px solid #e5e7eb;
  border-top-color: #f97316;
  border-radius: 50%;
  animation: spin 0.8s linear infinite;
}

@keyframes spin {
  to { transform: rotate(360deg); }
}

/* Result */
.result-area {
  width: 100%;
  max-width: 400px;
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 14px;
}

#result-img {
  width: 100%;
  border-radius: 12px;
  object-fit: cover;
  max-height: 300px;
}

.verdict {
  font-size: 22px;
  font-weight: 700;
  padding: 8px 20px;
  border-radius: 10px;
  text-align: center;
}

.verdict.hot-dog {
  background: #ecfdf5;
  color: #065f46;
}

.verdict.not-hot-dog {
  background: #fef2f2;
  color: #991b1b;
}

.explanation {
  font-size: 15px;
  line-height: 1.5;
  color: #4b5563;
  text-align: center;
  padding: 0 8px;
}

.try-again-btn {
  padding: 10px 24px;
  border: none;
  border-radius: 10px;
  background: #f97316;
  color: #fff;
  font-size: 15px;
  font-weight: 600;
  cursor: pointer;
  transition: background 0.2s;
}

.try-again-btn:hover {
  background: #ea580c;
}

